using System;
using System.Data.SqlClient;

public class LoginValidator
{
    public bool ValidateLogin(string username, string password)
    {
        try
        {
            using (SqlConnection connection = new SqlConnection("Server=your_server;Database=your_database;User Id=your_username;Password=your_password;"))
            {
                connection.Open();

                string query = "SELECT COUNT(*) FROM Users WHERE Username=@username AND PasswordHash=@password";
                SqlCommand command = new SqlCommand(query, connection);
                command.Parameters.AddWithValue("@username", username);
                command.Parameters.AddWithValue("@password", password);

                int count = (int)command.ExecuteScalar();
                return count > 0;
            }
        }
        catch (SqlException ex)
        {
            Console.WriteLine("Error validating login: " + ex.Message);
            return false;
        }
    }
}